def format_report(title, data):
    """Format a report with a title and key-value data dict.
    Output: title centered in 40 chars with '=' border,
    then each key: value pair on its own line."""
    lines = []
    lines.append('=' * 40)
    lines.append(title.center(40))
    lines.append('=' * 40)
    for key, value in data.items():
        lines.append(f'{key}: {value}')
    return '\n'.join(lines)

def create_table(headers, rows):
    """Create a text table with headers and rows.
    Columns should be separated by ' | ' with a dashed separator line."""
    all_rows = [headers] + rows
    col_widths = []
    for i in range(len(headers)):
        max_w = max(len(str(row[i])) for row in all_rows)
        col_widths.append(max_w)
    def format_row(row):
        cells = [str(row[i]).ljust(col_widths[i]) for i in range(len(headers))]
        return ' | '.join(cells)
    lines = []
    lines.append(format_row(headers))
    lines.append('-+-'.join('-' * w for w in col_widths))
    for row in rows:
        lines.append(format_row(row))
    return '\n'.join(lines)

def generate_summary(text):
    """Return a summary dict with 'lines', 'words', 'chars', and
    'avg_word_length' (rounded to 1 decimal)."""
    words = text.split()
    num_words = len(words)
    avg_len = round(sum(len(w) for w in words) / num_words, 1) if num_words > 0 else 0.0
    return {
        'lines': len(text.splitlines()) if text else 0,
        'words': num_words,
        'chars': len(text),
        'avg_word_length': avg_len
    }

def wrap_text(text, width):
    """Wrap text to the specified width, breaking at word boundaries.
    Return the wrapped text as a string with newlines."""
    words = text.split()
    lines = []
    current_line = []
    current_length = 0
    for word in words:
        if current_length + len(word) + len(current_line) > width and current_line:
            lines.append(' '.join(current_line))
            current_line = [word]
            current_length = len(word)
        else:
            current_line.append(word)
            current_length += len(word)
    if current_line:
        lines.append(' '.join(current_line))
    return '\n'.join(lines)
